type Cell = [number, number]; // [x, y]

function countLiveNeighbors(cells: Cell[], [x, y]: Cell): number {
  return cells.filter(
    ([nx, ny]) =>
      !(nx === x && ny === y) &&
      Math.abs(nx - x) <= 1 &&
      Math.abs(ny - y) <= 1,
  ).length;
}

function survives(liveNeighbors: number): boolean {
  return liveNeighbors === 2 || liveNeighbors === 3;
}

/**
 * Computes the next generation of live cells from the current live cells,
 * applying Conway's rules.
 */
export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => survives(countLiveNeighbors(cells, cell)));
}

