  it("returns an empty array for an empty grid — [] → []", () => {
    expect(nextGeneration([])).toEqual([]);
  });

  it("a single live cell dies of underpopulation — [(0,0)] → []", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
